// n8n Code node
// Mode: Run Once for All Items
//
// Input: one item per ACTIVE job ad
// Output: one item per company_domain
//
// Expected input fields per job (best effort; code is defensive):
// - company_domain
// - title
// - external_url OR url
// - date_posted OR created_at OR posted_at
// - location OR city / state / country
// - job_sources (array with source fields) OR source
// - applicants_count (optional)
//
// Notes:
// - No historical storage is used.
// - Since this is an active digest, job_active_cs_listings_total = number of active rows in input for that company.
// - "Hottest job" logic:
//    1) highest applicants_count, if at least one job for the company has a numeric applicants_count
//    2) otherwise most recent posted date
// - jobs_last_7_days / jobs_last_30_days are based on the best available posted date field.

function normalizeDomain(value) {
  return String(value || '')
    .toLowerCase()
    .trim()
    .replace(/^www\./, '');
}

function toDate(value) {
  if (!value) return null;
  const d = new Date(value);
  return Number.isNaN(d.getTime()) ? null : d;
}

function toIsoDate(value) {
  const d = toDate(value);
  return d ? d.toISOString() : '';
}

function getPostedDate(job) {
  return (
    job.date_posted ||
    job.posted_at ||
    job.created_at ||
    job.createdAt ||
    job.updated_at ||
    ''
  );
}

function parseApplicantsCount(value) {
  if (value === null || value === undefined || value === '') return null;

  // already numeric
  if (typeof value === 'number' && Number.isFinite(value)) return value;

  const str = String(value).trim().toLowerCase();

  // common patterns:
  // "23", "23 applicants", "23+ applicants", "100+", "over 200 applicants"
  const match = str.match(/(\d+(?:[.,]\d+)?)/);
  if (!match) return null;

  const num = Number(match[1].replace(',', '.'));
  return Number.isFinite(num) ? num : null;
}

function buildLocation(job) {
  if (job.location && String(job.location).trim()) {
    return String(job.location).trim();
  }

  const parts = [
    job.city,
    job.state,
    job.country
  ]
    .map(v => String(v || '').trim())
    .filter(Boolean);

  return parts.join(', ');
}

function extractSources(job) {
  const out = new Set();

  // single source field
  if (job.source) {
    out.add(String(job.source).trim());
  }

  // nested job_sources array
  if (Array.isArray(job.job_sources)) {
    for (const s of job.job_sources) {
      if (!s) continue;
      if (s.source) out.add(String(s.source).trim());
      else if (s.name) out.add(String(s.name).trim());
    }
  }

  return [...out].filter(Boolean);
}

function choosePrimaryLocation(locationCounts) {
  let bestLocation = '';
  let bestCount = -1;

  for (const [location, count] of Object.entries(locationCounts)) {
    if (count > bestCount) {
      bestLocation = location;
      bestCount = count;
    }
  }

  return bestLocation;
}

function chooseHottestJob(jobs) {
  // First preference: highest applicants_count if present
  const jobsWithApplicants = jobs
    .map(job => ({
      job,
      applicants_count_num: parseApplicantsCount(job.applicants_count),
      postedDate: toDate(getPostedDate(job)),
    }))
    .filter(x => x.applicants_count_num !== null);

  if (jobsWithApplicants.length > 0) {
    jobsWithApplicants.sort((a, b) => {
      if (b.applicants_count_num !== a.applicants_count_num) {
        return b.applicants_count_num - a.applicants_count_num;
      }

      const aTime = a.postedDate ? a.postedDate.getTime() : 0;
      const bTime = b.postedDate ? b.postedDate.getTime() : 0;
      return bTime - aTime;
    });

    return jobsWithApplicants[0].job;
  }

  // Fallback: most recent posted date
  const sortedByDate = [...jobs].sort((a, b) => {
    const aTime = toDate(getPostedDate(a))?.getTime() || 0;
    const bTime = toDate(getPostedDate(b))?.getTime() || 0;
    return bTime - aTime;
  });

  return sortedByDate[0] || null;
}

const inputJobs = $input.all().map(i => i.json);
const now = new Date();
const ms7 = 7 * 24 * 60 * 60 * 1000;
const ms30 = 30 * 24 * 60 * 60 * 1000;

const companies = {};

// Group jobs by company_domain
for (const job of inputJobs) {
  const companyDomain = normalizeDomain(job.company_domain);

  if (!companyDomain) continue;

  if (!companies[companyDomain]) {
    companies[companyDomain] = {
      company_domain: companyDomain,
      jobs: [],
      locationCounts: {},
      sourceSet: new Set(),
      latestPostedDate: null,
      earliestPostedDate: null,
    };
  }

  const company = companies[companyDomain];
  company.jobs.push(job);

  // location aggregation
  const location = buildLocation(job);
  if (location) {
    company.locationCounts[location] = (company.locationCounts[location] || 0) + 1;
  }

  // source aggregation
  const sources = extractSources(job);
  for (const source of sources) {
    company.sourceSet.add(source);
  }

  // posted date range
  const postedDate = toDate(getPostedDate(job));
  if (postedDate) {
    if (!company.latestPostedDate || postedDate > company.latestPostedDate) {
      company.latestPostedDate = postedDate;
    }
    if (!company.earliestPostedDate || postedDate < company.earliestPostedDate) {
      company.earliestPostedDate = postedDate;
    }
  }
}

// Build company digest rows
const result = [];

for (const companyDomain of Object.keys(companies)) {
  const company = companies[companyDomain];
  const jobs = company.jobs;

  const jobsLast7Days = jobs.filter(job => {
    const posted = toDate(getPostedDate(job));
    return posted ? (now - posted) <= ms7 : false;
  }).length;

  const jobsLast30Days = jobs.filter(job => {
    const posted = toDate(getPostedDate(job));
    return posted ? (now - posted) <= ms30 : false;
  }).length;

  const hottestJob = chooseHottestJob(jobs) || {};
  const hottestPosted = getPostedDate(hottestJob);

  result.push({
    json: {
      company_domain: company.company_domain,

      job_active_cs_listings_total: jobs.length,
      jobs_last_7_days: jobsLast7Days,
      jobs_last_30_days: jobsLast30Days,

      job_signal_detected: jobs.length > 0,

      top_job_title: hottestJob.title || '',
      top_job_url: hottestJob.external_url || hottestJob.url || '',
      top_job_posted_at: toIsoDate(hottestPosted),

      top_job_applicants_count: parseApplicantsCount(hottestJob.applicants_count),
      top_job_location: buildLocation(hottestJob),

      primary_location: choosePrimaryLocation(company.locationCounts),
      locations_count: Object.keys(company.locationCounts).length,

      sources: [...company.sourceSet],
      sources_count: company.sourceSet.size,

      last_job_posted_at: company.latestPostedDate ? company.latestPostedDate.toISOString() : '',
      first_job_seen_at: company.earliestPostedDate ? company.earliestPostedDate.toISOString() : '',
    }
  });
}

// Optional: sort companies by active listings desc, then recent activity desc
result.sort((a, b) => {
  if (b.json.job_active_cs_listings_total !== a.json.job_active_cs_listings_total) {
    return b.json.job_active_cs_listings_total - a.json.job_active_cs_listings_total;
  }
  return b.json.jobs_last_7_days - a.json.jobs_last_7_days;
});

return result;

// n8n Code node
// Mode: Run Once for All Items
//
// Input: rows that exist only in B
// HubSpot source node: Filter1

function normalizeDomain(value) {
  return String(value || '')
    .toLowerCase()
    .trim()
    .replace(/^www\./, '');
}

// Build HubSpot domain -> ids map
const hsItems = $items('Filter Active Companies', 0, 0) || [];
const hubspotByDomain = {};

for (const item of hsItems) {
  const row = item.json || {};
  const domain = normalizeDomain(row.properties.website.versions[0].value);
  if (!domain) continue;

  hubspotByDomain[domain] = {
    company_id: row.companyId ?? null,
    portal_id: row.portalId ?? null,
  };
}

// Join current input with HubSpot map
const out = [];

for (const item of $input.all()) {
  const row = { ...(item.json || {}) };
  const domain = normalizeDomain(row.company_domain);

  const hs = hubspotByDomain[domain] || {};

  row.company_domain = domain;
  row.company_id = hs.company_id ?? null;
  row.portal_id = hs.portal_id ?? null;

  out.push({ json: row });
}

return out;

// n8n Code node
// Mode: Run Once for All Items
//
// Input: comparison node "Different" output items
// Looks up HubSpot company ID from node: Filter1

function normalizeDomain(value) {
  return String(value || '')
    .toLowerCase()
    .trim()
    .replace(/^www\./, '');
}

function toNumber(value) {
  if (value === null || value === undefined || value === '') return null;
  const num = Number(value);
  return Number.isFinite(num) ? num : null;
}

function toBoolean(value) {
  if (typeof value === 'boolean') return value;
  if (value === 1 || value === '1') return true;
  if (value === 0 || value === '0') return false;
  if (typeof value === 'string') {
    const v = value.toLowerCase().trim();
    if (v === 'true') return true;
    if (v === 'false') return false;
  }
  return value;
}

// --- Build HubSpot domain -> companyId map from Filter1 ---
const hsItems = $items('Filter Active Companies', 0, 0) || [];
const hubspotByDomain = {};

for (const item of hsItems) {
  const row = item.json || {};
  const domain = normalizeDomain(row.properties?.domain?.value);
  if (!domain) continue;

  hubspotByDomain[domain] = {
    company_id: row.companyId ?? null,
    portal_id: row.portalId ?? null,
  };
}

// --- Normalize comparison rows ---
const inputItems = $input.all();
const output = [];

for (const item of inputItems) {
  const row = item.json || {};
  const keys = row.keys || {};
  const same = row.same || {};
  const different = row.different || {};

  // Start from unchanged values
  const normalized = { ...same };

  // Overlay changed fields with inputB values
  for (const [field, diffValue] of Object.entries(different)) {
    if (diffValue && typeof diffValue === 'object' && 'inputB' in diffValue) {
      normalized[field] = diffValue.inputB;
    }
  }

  // Ensure company_domain exists
  if (!normalized.company_domain && keys.company_domain) {
    normalized.company_domain = keys.company_domain;
  }

  normalized.company_domain = normalizeDomain(normalized.company_domain);

  // Attach HubSpot company ID
  const hs = hubspotByDomain[normalized.company_domain] || {};
  normalized.company_id = hs.company_id ?? null;
  normalized.portal_id = hs.portal_id ?? null;

  // --- Change analysis ---
  // Current (B) and previous (A) active counts
  let currentActive = toNumber(normalized.job_active_cs_listings_total);
  let previousActive = currentActive;

  if (
    different.job_active_cs_listings_total &&
    typeof different.job_active_cs_listings_total === 'object'
  ) {
    previousActive = toNumber(different.job_active_cs_listings_total.inputA);
    currentActive = toNumber(different.job_active_cs_listings_total.inputB);
  }

  let delta = null;
  let trend = 'unchanged';
  let rose = false;
  let fell = false;

  if (previousActive !== null && currentActive !== null) {
    delta = currentActive - previousActive;
    if (delta > 0) {
      trend = 'rose';
      rose = true;
    } else if (delta < 0) {
      trend = 'fell';
      fell = true;
    }
  }

  // Top title change
  let previousTopTitle = normalized.top_job_title || '';
  let currentTopTitle = normalized.top_job_title || '';
  let topTitleChanged = false;

  if (different.top_job_title && typeof different.top_job_title === 'object') {
    previousTopTitle = different.top_job_title.inputA || '';
    currentTopTitle = different.top_job_title.inputB || '';
    topTitleChanged = previousTopTitle !== currentTopTitle;
    normalized.top_job_title = currentTopTitle;
  }

  // Normalize common field types
  normalized.job_signal_detected = toBoolean(normalized.job_signal_detected);

  // Add derived fields
  normalized.previous_job_active_cs_listings_total = previousActive;
  normalized.job_active_cs_listings_delta = delta;
  normalized.job_active_cs_listings_trend = trend;
  normalized.job_ads_rose = rose;
  normalized.job_ads_fell = fell;

  normalized.previous_top_job_title = previousTopTitle;
  normalized.top_title_changed = topTitleChanged;

  // Optional: mark this as an update row
  normalized.needs_update = true;
  normalized.update_type = 'comparison_diff';

  output.push({ json: normalized });
}

return output;

// n8n Code node
