  out.push({
    json: {
      company_domain: domain,
      company_id: hs.company_id ?? null,
      portal_id: hs.portal_id ?? null,

      job_active_cs_listings_total: 0,
      jobs_last_7_days: 0,
      jobs_last_30_days: 0,
